<?php
namespace Tests\Feature\Admin\Content;use App\Domain\WorldMaps\Exceptions\WorldMapConcurrencyException;use App\Domain\WorldMaps\WorldMapAdminService;use App\Models\Region;use App\Models\User;use App\Models\World;use App\Models\WorldMap;use App\Models\WorldMapArea;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use InvalidArgumentException;use Tests\TestCase;
class WorldMapAdminTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();$this->seed(WorldCatalogSeeder::class);Storage::fake('public');config(['world_maps.disk'=>'public','world_maps.minimum_width'=>100,'world_maps.minimum_height'=>100,'game_admin.emails'=>['map-admin@example.test']]);$this->admin=User::factory()->create(['email'=>'map-admin@example.test']);}private function map($context=[]){Storage::disk('public')->put('maps/test.png','image');return WorldMap::create(array_merge(['world_id'=>World::first()->id,'region_id'=>null,'code'=>'admin_map_'.uniqid(),'name'=>'Admin Map','image_disk'=>'public','image_path'=>'maps/test.png','original_width'=>640,'original_height'=>360,'mime_type'=>'image/png','file_size'=>5,'version'=>1,'status'=>'active','is_default'=>false,'sort_order'=>0],$context));}private function areaData($status='active'){return['code'=>'area_'.uniqid(),'name'=>'Area','description'=>'Plain information','polygon_points'=>['coordinate_system'=>'normalized','points'=>[['x'=>0.1,'y'=>0.1],['x'=>0.5,'y'=>0.1],['x'=>0.2,'y'=>0.5]]],'action_type'=>'info','display_mode'=>'panel','z_index'=>0,'fill_color'=>'#0d6efd','fill_opacity'=>0.25,'stroke_color'=>'#ffffff','stroke_width'=>2,'hover_fill_color'=>'#ffc107','hover_fill_opacity'=>0.45,'status'=>$status,'sort_order'=>0,'available_from'=>null,'available_until'=>null];}public function test_admin_access_upload_and_normal_user_forbidden(){$this->actingAs($this->admin)->get(route('admin.content.world-maps.index'))->assertOk();$normal=User::factory()->create();$this->actingAs($normal)->get(route('admin.content.world-maps.index'))->assertForbidden();$world=World::first();$response=$this->actingAs($this->admin)->post(route('admin.content.world-maps.store'),['world_id'=>$world->id,'code'=>'uploaded_map','name'=>'Uploaded','image'=>UploadedFile::fake()->image('map.png',640,360),'status'=>'active','is_default'=>1,'sort_order'=>0]);$response->assertRedirect();$map=WorldMap::where('code','uploaded_map')->firstOrFail();$this->assertSame(640,$map->original_width);$this->assertTrue(Storage::disk('public')->exists($map->image_path));}public function test_defaults_deactivation_and_concurrency_are_authoritative(){$service=app(WorldMapAdminService::class);$one=$this->map();$two=$this->map();$base=['world_id'=>$one->world_id,'region_id'=>null,'name'=>$one->name,'code'=>$one->code,'description'=>null,'status'=>'active','is_default'=>true,'sort_order'=>0,'version'=>1];$service->saveMap($base,$one);$base['code']=$two->code;$base['name']=$two->name;$base['version']=1;$service->saveMap($base,$two);$this->assertFalse($one->fresh()->is_default);$this->assertTrue($two->fresh()->is_default);$service->deactivateMap($two,$two->fresh()->version);$this->assertFalse($two->fresh()->is_default);try{$service->deactivateMap($one,1);$this->fail();}catch(WorldMapConcurrencyException $e){$this->assertTrue(true);}}public function test_draft_incomplete_reserved_activation_and_independent_area_versions(){$map=$this->map();$service=app(WorldMapAdminService::class);$draft=$service->saveArea($map,array_merge($this->areaData('draft'),['polygon_points'=>null,'action_type'=>'seasonal_event','description'=>null]));$this->assertSame('draft',$draft->status);try{$service->activateArea($map,$draft,$draft->version);$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('reserved',$e->getMessage());}$a=$service->saveArea($map,$this->areaData());$b=$service->saveArea($map,$this->areaData());$aVersion=$a->version;$bVersion=$b->version;$data=$this->areaData();$data['code']=$a->code;$data['version']=$aVersion;$service->saveArea($map,$data,$a);$this->assertSame($bVersion,$b->fresh()->version);}public function test_map_cannot_target_itself_but_two_maps_can_link(){$service=app(WorldMapAdminService::class);$a=$this->map();$b=$this->map();$data=$this->areaData();$data['action_type']='map';$data['description']=null;$data['target_world_map_id']=$a->id;try{$service->saveArea($a,$data);$this->fail();}catch(InvalidArgumentException $e){$this->assertStringContainsString('own',$e->getMessage());}$data['target_world_map_id']=$b->id;$service->saveArea($a,$data);$data['code']='reverse';$data['target_world_map_id']=$a->id;$service->saveArea($b,$data);$this->assertSame(2,WorldMapArea::count());}}
